import{_ as r,o as t,c as e,ae as l}from"./chunks/framework.BeMCGcrk.js";const b=JSON.parse('{"title":"阿里巴巴：一个被低估的AI巨头正在崛起","description":"","frontmatter":{},"headers":[],"relativePath":"blog/alibaba-bullish.md","filePath":"blog/alibaba-bullish.md"}'),o={name:"blog/alibaba-bullish.md"};function i(n,a,s,h,d,p){return t(),e("div",null,[...a[0]||(a[0]=[l('<h1 id="阿里巴巴-一个被低估的ai巨头正在崛起" tabindex="-1">阿里巴巴：一个被低估的AI巨头正在崛起 <a class="header-anchor" href="#阿里巴巴-一个被低估的ai巨头正在崛起" aria-label="Permalink to &quot;阿里巴巴：一个被低估的AI巨头正在崛起&quot;">​</a></h1><p><strong>2026年，应该是重新认识阿里巴巴的时刻了。</strong></p><hr><h2 id="被市场忽视的巨头" tabindex="-1">被市场忽视的巨头 <a class="header-anchor" href="#被市场忽视的巨头" aria-label="Permalink to &quot;被市场忽视的巨头&quot;">​</a></h2><p>过去几年，阿里巴巴的股价表现确实不尽如人意。但仔细看基本面，你会发现一个截然不同的故事正在上演——<strong>阿里巴巴已经从一家电商公司，悄然转型为一家AI驱动的科技巨头。</strong></p><h2 id="ai-不仅仅是大模型" tabindex="-1">AI 不仅仅是大模型 <a class="header-anchor" href="#ai-不仅仅是大模型" aria-label="Permalink to &quot;AI 不仅仅是大模型&quot;">​</a></h2><h3 id="通义千问-国产大模型的领头羊" tabindex="-1">通义千问：国产大模型的领头羊 <a class="header-anchor" href="#通义千问-国产大模型的领头羊" aria-label="Permalink to &quot;通义千问：国产大模型的领头羊&quot;">​</a></h3><p>阿里云的通义千问（Qwen）系列，已经成为国内最具竞争力的大模型之一：</p><ul><li><strong>开源策略</strong>：Qwen2.5系列全面开源，让开发者可以自由部署和微调</li><li><strong>性能领先</strong>：在多项基准测试中，Qwen2.5已经接近甚至超越GPT-4</li><li><strong>生态丰富</strong>：配合阿里云的算力支持，形成了从模型到应用的完整闭环</li></ul><h3 id="阿里云-ai时代的基础设施" tabindex="-1">阿里云：AI时代的基础设施 <a class="header-anchor" href="#阿里云-ai时代的基础设施" aria-label="Permalink to &quot;阿里云：AI时代的基础设施&quot;">​</a></h3><p>阿里云目前是国内市场份额第一的云计算厂商，而在AI时代，云计算就是基础设施：</p><ul><li><strong>算力资源</strong>：阿里云拥有国内最完善的GPU算力资源</li><li><strong>模型服务</strong>：通义灵码、通义智文等AI应用已经落地</li><li><strong>企业服务</strong>：越来越多的企业开始使用阿里云的AI能力</li></ul><h2 id="电商基本面依然稳固" tabindex="-1">电商基本面依然稳固 <a class="header-anchor" href="#电商基本面依然稳固" aria-label="Permalink to &quot;电商基本面依然稳固&quot;">​</a></h2><p>尽管增速放缓，但阿里巴巴的电商业务依然是现金牛：</p><ul><li><strong>用户规模</strong>：淘宝+天猫的活跃用户数依然遥遥领先</li><li><strong>GMV</strong>：依然是国内最大的电商平台</li><li><strong>盈利能力</strong>：利润率持续改善，运营效率不断提升</li></ul><h2 id="估值-真的贵吗" tabindex="-1">估值：真的贵吗？ <a class="header-anchor" href="#估值-真的贵吗" aria-label="Permalink to &quot;估值：真的贵吗？&quot;">​</a></h2><p>对比美国科技巨头动辄30-40倍的市盈率，阿里巴巴目前只有15倍左右，这对于一家正在AI赛道发力的科技公司来说，<strong>明显偏低</strong>。</p><hr><h2 id="写在最后" tabindex="-1">写在最后 <a class="header-anchor" href="#写在最后" aria-label="Permalink to &quot;写在最后&quot;">​</a></h2><p>阿里巴巴正在经历从电商公司到AI科技公司的转型阵痛期。市场往往过度关注短期的业绩波动，而忽视了长期的结构性变化。</p><p>当AI时代全面到来，拥有最强算力、最丰富应用场景、最成熟企业服务体系的阿里巴巴，会是最大的受益者之一。</p><p><strong>不是建议买入，只是觉得，在一片悲观声中，可能需要重新审视这家公司的价值了。</strong></p><hr><p><em>免责声明：本文仅供参考，不构成投资建议。投资有风险，入市需谨慎。</em></p>',24)])])}const g=r(o,[["render",i]]);export{b as __pageData,g as default};
